'use client';

import { createAd } from '@/entities/ad/api/createAd';
import {
  CreateAdForm as TypeCreateAdForm,
  createAdSchema,
} from '@/entities/ad/model/createAdSchema';
import { zodResolver } from '@hookform/resolvers/zod';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { useForm } from 'react-hook-form';

export default function CreateAdForm() {
  const queryClient = useQueryClient();

  const mutation = useMutation({
    mutationFn: createAd,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['ads'] });
    },
  });

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<TypeCreateAdForm>({
    resolver: zodResolver(createAdSchema),
  });

  const onSubmit = (data: TypeCreateAdForm) => {
    mutation.mutate(data);
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)} style={{ maxWidth: 400 }}>
      <h2>Create Ad</h2>

      <input type="text" placeholder="Title" {...register('title')} />
      {errors.title && <p>{errors.title.message}</p>}

      <input
        type="number"
        placeholder="Price"
        {...register('price', { valueAsNumber: true })}
      />
      {errors.price && <p>{errors.price.message}</p>}

      <input
        type="text"
        placeholder="Description"
        {...register('description')}
      />
      {errors.description && <p>{errors.description.message}</p>}

      <button type="submit">
        {mutation.isPending ? 'Creating...' : 'Create'}
      </button>
    </form>
  );
}
